23	// ListModels returns models matching the filter, with full metadata.
24	// Empty filter returns all models from every reachable provider.
25	func (s *service) ListModels(ctx context.Context, filter ModelFilter) ([]ModelInfo, error) {
26		if filter.Harness != "" && harnesses.ResolveHarnessAlias(filter.Harness) != "fiz" {
27			return s.listModelsForSubprocessHarness(filter), nil
28		}
29	
30		sc := s.opts.ServiceConfig
31		if sc == nil {
32			return nil, fmt.Errorf("service: no ServiceConfig provided; pass ServiceOptions.ServiceConfig")
33		}
34	
35		// Load the model catalog once for cross-referencing.
36		cat, _ := modelcatalog.Default() // ignore error: catalog miss is non-fatal
37		cacheRoot, err := serviceSnapshotCacheRoot()
38		if err != nil {
39			return nil, err
40		}
41		snapshot, err := assembleModelSnapshotFromServiceConfigWithOptions(ctx, sc, cat, cacheRoot, modelsnapshot.AssembleOptions{Refresh: modelsnapshot.RefreshForce})
42		if err != nil {
43			return nil, err
44		}
45		return s.listModelsFromSnapshot(ctx, sc, cat, snapshot, filter), nil
46	}
