599	func betterModelVariantMatch(candidate ModelEntry, candidateID string, best ModelEntry, bestID string) bool {
600		candidateStatus := normalizedStatus(candidate.Status)
601		bestStatus := normalizedStatus(best.Status)
602		if candidateStatus != bestStatus {
603			return statusRank(candidateStatus) > statusRank(bestStatus)
604		}
605		if candidate.Power != best.Power {
606			return candidate.Power > best.Power
607		}
608		if candidate.ContextWindow != best.ContextWindow {
609			return candidate.ContextWindow > best.ContextWindow
610		}
611		if candidate.ExactPinOnly != best.ExactPinOnly {
612			return !candidate.ExactPinOnly && best.ExactPinOnly
613		}
614		return candidateID < bestID
615	}
